INSERT INTO "Game" ("id", "name", "description", "imageUrl", "availableDifficulties", "availableGameModes") VALUES
(6, 'NACIONES', 'NACIONES es un juego en el que debes completar una formación con futbolistas de 11 países distintos. Los países aparecen en orden aleatorio y debes añadir un jugador de cada país para llenar el once usando el campo para escribir. Si no conoces ningún jugador, hay un botón para cambiar de país, pero aplica una sanción de 5 segundos antes de que aparezca el siguiente. Modo versus 1v1: ambos comparten el mismo tablero y, cuando uno elige un futbolista para una posición, esa casilla queda bloqueada para el otro. Gana quien tenga más casillas llenas al finalizar la partida.', '/minigames/naciones.png', ARRAY['Fácil','Medio','Difícil'], ARRAY['Jugar Solo','Jugar con Amigo']),
(7, 'CLUBES', 'CLUBES es un juego en el que debes completar una formación con futbolistas de 11 clubes distintos. Los clubes aparecen en orden aleatorio y debes añadir un jugador de cada club para completar el once usando el campo para escribir. Si no conoces ningún jugador, hay un botón para cambiar de club, con sanción de 5 segundos antes del siguiente. Modo versus 1v1: el tablero es compartido; si un jugador coloca a alguien en una posición, esa casilla queda bloqueada para el rival. Gana quien tenga más casillas llenas al finalizar la partida.', '/minigames/clubes.png', ARRAY['Fácil','Medio','Difícil'], ARRAY['Jugar Solo','Jugar con Amigo']),
(8, 'GRID', 'GRID es un juego 3×3 (tipo "tic-tac-toe" de fútbol) con criterios en filas y columnas. Debes llenar las 9 casillas con futbolistas que cumplan simultáneamente la fila y la columna. Primero seleccionas una casilla de las 9 y después usas el campo de escribir para buscar un jugador que encaje en esa casilla. Modo versus 1v1: ambos comparten la misma grilla; cada elección bloquea esa casilla para el otro. Gana quien tenga más casillas llenas al finalizar la partida.', '/minigames/grid.png', ARRAY['Fácil','Medio','Difícil'], ARRAY['Jugar Solo','Jugar con Amigo']),
(9, 'BINGO', 'BINGO es un juego donde aparecen futbolistas uno por uno y debes hacer clic en la casilla de la categoría donde encajan (clubes, países, posiciones, pierna buena, liga y dorsal). Reglas: si eliges una categoría que NO encaja con el futbolista mostrado, recibes una sanción de 3 segundos antes de poder volver a jugar. Botón "Skip": si no sabes dónde encaja, puedes saltarlo pero aplica una sanción de 1 segundo. Llena las 12 casillas para lograr ¡Bingo! Modo versus 1v1: ambos comparten el mismo tablero; cuando uno asigna correctamente un jugador a una casilla, esta queda bloqueada para el rival. Gana quien tenga más casillas llenas al finalizar la partida.', '/minigames/bingo.png', ARRAY['Fácil','Medio','Difícil'], ARRAY['Jugar Solo','Jugar con Amigo']),
(10, 'BINGO ALT', 'BINGO ALT es un juego donde aparecen categorías una por una y debes hacer clic en la casilla del futbolista que encaje con ella (clubes, países, posiciones, pierna buena, liga y dorsal). Reglas: si eliges un futbolista que NO encaja con la categoría activa, recibes una sanción de 3 segundos antes de poder volver a jugar. Botón "Skip": si no sabes a qué futbolista asignar la categoría, puedes saltarla pero aplica una sanción de 1 segundo. Llena las 12 casillas para lograr ¡Bingo! Modo versus 1v1: ambos comparten el mismo tablero; cuando uno asigna correctamente una categoría a un futbolista, la casilla queda bloqueada para el rival. Gana quien tenga más casillas llenas al finalizar la partida.', '/minigames/bingoalt.png', ARRAY['Fácil','Medio','Difícil'], ARRAY['Jugar Solo','Jugar con Amigo'])
